var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"20년 전","JPN":"20年前","ENG":"20 years ago","TWN":"20年前","DEU":"20 years ago","FRA":"20 years ago"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"대정화 전쟁 <color=#ffd34c>북극점 공방전</color>","JPN":"大浄化戦争<color=#ffd34c>北極点攻防戦</color>","ENG":"Grand Purification War <color=#ffd34c>North Pole Battle</color>","TWN":"大淨化戰爭<color=#ffd34c>北極點攻防戰</color>","DEU":"Grand Purification War <color=#ffd34c>North Pole Battle</color>","FRA":"Grand Purification War <color=#ffd34c>North Pole Battle</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"국제 연합군 제3 주둔지\\n<color=#ffd34c>침식전 AB-014</color>","JPN":"国際連合軍第3駐屯地\\n<color=#ffd34c>侵食戦AB-014</color>","ENG":"[[","TWN":"國際聯合軍第3駐屯地\\n<color=#ffd34c>侵蝕戰AB-014</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"3번 도로가 장악 당했습니다!","JPN":"3番道路を乗っ取られました！","ENG":"Route 3 is compromised!","TWN":"3號公路被佔領了！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"예비대! 통신 두절!","JPN":"予備隊！　通信途絶！","ENG":"We've lost contact with the reserves! No comms!","TWN":"預備隊！通信中斷！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"전방에 있던 기갑사단도 퇴각 중입니다. 이대로는 방어선을 유지할 수 없습니다.","JPN":"先方の機甲師団も退却中です。このままでは、防御線を維持できません。","ENG":"The armored division is also retreating from the front lines. We won't be able to hold the line of defense at this rate.","TWN":"前方的裝甲兵團也在撤退中，再這樣下去無法維持防線。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"최악의 경우에는 전멸할 수도…….","JPN":"最悪の場合、全滅する可能性も……","ENG":"If worst comes to worst... we may be facing annihilation...","TWN":"最糟的情況有可能會全軍覆沒……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"태스크포스는? 증원은 없나?","JPN":"タスクフォースカンパニーは？　増員はないのか？","ENG":"What about the TASKFORCE? Aren't they sending any reinforcements?","TWN":"特遣勢力呢？沒有增援嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"안토노프 대령의 부대가 호출에 응답하긴 했지만...... 세타 포인트에서 적 주력과 교전 중이라고 합니다.","JPN":"アントノフ大佐の部隊が呼び出しに応じましたが……\\nシータポイントで、敵の主力と交戦中だそうです。","ENG":"Colonel Antonov's unit did answer our call... But they're engaging the enemy's main effort at Theta Point.","TWN":"安東諾夫中將的部隊雖然有回應……但他們說正在賽塔點與敵軍主力交戰中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"더 늦기 전에 퇴각하셔야 합니다.","JPN":"手遅れになる前に、退却すべきです。","ENG":"We must fall back before it's too late.","TWN":"我們得盡快撤退才行。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"......저기 저거 보이나?","JPN":"……あれが見えるか？","ENG":"You see that over there?","TWN":"……你有看到那個嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"저기 보호구역에 모여 있는 민간인들 말일세.","JPN":"あの保護区域に集まっている民間人を見ろ。","ENG":"I mean those civilians huddled up in the protection zone.","TWN":"那些聚集在保護區的平民。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"우리가 도망치고 나면 저 사람들은 누가 지키나?","JPN":"俺たちが逃げたら、あの人たちは誰が守るんだ？","ENG":"Who's going to protect them if we flee?","TWN":"如果我們逃跑了，誰來守護他們？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"사단장님, 사단장님!","JPN":"指揮官、指揮官！","ENG":"Commander! Commander!","TWN":"師團長、師團長！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"뭔가?","JPN":"何だ？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워 소속의 연구원이라는 사람이 사단장님께 대면을 요청했습니다.","JPN":"フューチャーアットウォー所属の研究員と名乗る者が、指揮官に面談を要請しました。","ENG":"Some researcher from Future-at-War has requested a meeting with you.","TWN":"有個自稱是天啟兵器的研究員要求見您。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"상황을 타개하는 데 도움을 드릴 수 있다면서요.","JPN":"現状を打開するのに役立つはずだと言っています。","ENG":"They say they've got something that could pull us out of this rut.","TWN":"他說能提出解決當前局勢的方法。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"퓨처 앳 워?","JPN":"フューチャーアットウォー？","ENG":"Future-at-War?","TWN":"天啟兵器？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그 왜, 연합군 전략 회의에 애들 장난감 같은 거 들고 나왔다던 놈들 아닙니까.","JPN":"えっと、確か……連合軍の戦略会議に、子供のオモチャのようなものを持ち込んだやつらです。","ENG":"You know, the nerds who brought those fancy toys at the combined forces' strategy meeting.","TWN":"就是那些在聯軍戰略會議像小孩一樣拿著玩具出現的傢伙吧？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"그런데 너 어디 소속이야?","JPN":"お前、どこの所属だ？","ENG":"By the way, what's your unit, trooper?","TWN":"但你是哪個單位的？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"지금이 어떤 상황인데 그런 작자들이 진지에 들락거려! 통제 똑바로 안 해!","JPN":"こんな状況で、やつらが陣地に入っていいわけないだろ！　何を考えてるんだ！","ENG":"How could you let some outsiders like that go in and out of our positions in a situation like this?! Keep your security in check!","TWN":"現在這種情況還讓那種人進出營地！還不好好把關！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"아니, 안으로 들여 보내.","JPN":"いや、ここへ通せ。","ENG":"No... Let them come see me.","TWN":"算了，讓他進來吧。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AIDE_NPC_NULL_NULL","text":{"KOREA":"사단장님?!","JPN":"指揮官！？","ENG":"But sir?!","TWN":"師團長？！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"지금 다 죽을 판국인데 무슨 짓인들 못하겠나.","JPN":"どうせ、このままでは全滅だ。試せるものは、すべて試すしかない。","ENG":"We're all about to kick the bucket anyway. I don't see why not.","TWN":"現在大家都死到臨頭了，還有什麼不能試試看的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_NPC_NULL_NULL","text":{"KOREA":"잔말 말고 들여 보내게.","JPN":"さっさと通せ。","ENG":"Just let them in.","TWN":"別囉嗦，帶他進來。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"AIDE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_NPC_NULL_NULL","text":{"KOREA":"아, 예!","JPN":"あ、はい！","ENG":"Uh... Yes, sir!","TWN":"啊，是！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"그날, 보호 구역 안에 있던 모두가 숨을 죽였다.","JPN":"あの日、保護区域にいたみんなが、息を潜めた。","ENG":"That day, everyone inside the protected zone held their breath.","TWN":"那一天，保護區內的所有人都屏住呼吸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"이제는 기억조차 희미한 어린 날의 기억이지만,","JPN":"今ではうっすらとしか思い出せない、幼かった頃の記憶だけど。","ENG":"The memories are hazy now, just a child's blur.","TWN":"雖然現在對我來說已經是模糊到幾乎想不起來的童年記憶，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"단 하나만큼은 기억하고 있다.","JPN":"1つだけは、はっきりと覚えている。","ENG":"But one thing remains clear.","TWN":"但我仍清楚記得一件事。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"대 침식 섬멸 병기, 타이탄.","JPN":"対侵食殲滅兵器、タイタン。","ENG":"The Anti-Corruption annihilator, Titan.","TWN":"對抗侵蝕殲滅兵器，泰坦。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"전장에 도착했다.","JPN":"戦場に到着した。","ENG":"I'm at the battlefield.","TWN":"抵達戰場。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"그 거대하고 아름다운 것이 나를 구해줬다는 기억은.","JPN":"あの巨大かつ美しきものが私を助けてくれたという記憶。","ENG":"I remember that towering, beautiful thing saving me.","TWN":"記憶中，那巨大又美麗的東西拯救了我。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"내가 이 길을 걷기로 한 최초의 계기였다.","JPN":"それは私がこの道を歩むと決めた最初のきっかけだった。","ENG":"It was the first step that set me on this path.","TWN":"這也是我踏上這條路的契機。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_OMEN_NPC_QM","text":{"KOREA":"아직 늦지 않아서 다행이군요.","JPN":"間に合ってよかったです。","ENG":"I'm glad I wasn't late.","TWN":"還好還來得及。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"EMBER_OMEN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"L4_1","JPN":"L4_1","ENG":"L4_1","TWN":"L4_1","DEU":"L4_1","FRA":"L4_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"L5_1","JPN":"L5_1","ENG":"L5_1","TWN":"L5_1","DEU":"L5_1","FRA":"L5_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};